// Builds the weclapp article filter expression for the price sync query.
// Uses the active sales channels to determine source predicate.
return (() => {
const DEFAULT_SOURCE_SALES_CHANNEL = 'GROSS1';
const MINIMAL_ARTICLE_PROPERTIES = [
  'id','articleNumber','availableForSalesChannels',
  'articlePrices.id','articlePrices.version','articlePrices.currencyId',
  'articlePrices.customerId','articlePrices.description','articlePrices.endDate',
  'articlePrices.price','articlePrices.priceScaleType','articlePrices.priceScaleValue',
  'articlePrices.reductionAdditions','articlePrices.salesChannel','articlePrices.startDate',
];

function quoteFilterString(value) {
  const s = String(value ?? '');
  return '"' + s.replace(/\\/g,'\\\\').replace(/"/g,'\\"') + '"';
}

function normalizeStringList(value) {
  if (Array.isArray(value)) return value.map((e) => String(e || '').trim()).filter(Boolean);
  if (!value) return [];
  if (typeof value === 'string') {
    try { const p = JSON.parse(value); if (Array.isArray(p)) return p.map((e) => String(e||'').trim()).filter(Boolean); } catch(_) {}
    return value.split(',').map((e) => String(e||'').trim()).filter(Boolean);
  }
  return [String(value).trim()].filter(Boolean);
}

const constants = $('Constants').first().json;
const sourceSalesChannel = constants.sourceSalesChannel || DEFAULT_SOURCE_SALES_CHANNEL;
const effectiveTimestamp = constants.effectiveTimestamp;

const sourcePredicate = [
  '(salesChannel = ' + quoteFilterString(sourceSalesChannel) + ')',
  '(customerId null)',
  '(priceScaleValue = 0)',
  '((startDate null) or (startDate <= ' + Number(effectiveTimestamp) + '))',
  '((endDate null) or (endDate >= ' + Number(effectiveTimestamp) + '))',
  '(priceScaleType = "SCALE_FROM")',
].join(' and ');

const filterClauses = [
  '(articlePrices[' + sourcePredicate + '].salesChannel = ' + quoteFilterString(sourceSalesChannel) + ')',
];

const scopedArticleNumbers = normalizeStringList(constants.requestedArticleNumbers);
if (scopedArticleNumbers.length > 0) {
  filterClauses.push('(articleNumber in [' + scopedArticleNumbers.map((e) => quoteFilterString(e)).join(', ') + '])');
}

return [{
  json: {
    articleFilter: filterClauses.join(' and '),
    articleProperties: MINIMAL_ARTICLE_PROPERTIES.join(','),
    effectiveTimestamp,
  },
  pairedItem: { item: 0 },
}];
})();

// DRY-RUN: Price update is BLOCKED pending issue #30
// (article.updatePrices composite not wired to execute() in Weclapp.node.ts)
// This Code node runs the sync decision in dry-run mode only.
// In the fully-rebuilt workflow, the output of this node would feed into
// a weclapp article.updatePrices node — but that node has no execute() hook.
return (() => {
const DEFAULT_SOURCE_SALES_CHANNEL = 'GROSS1';
const DEFAULT_SCALE_VALUE = '0';
const WRITEABLE_PRICE_KEYS = ['id','version','currencyId','customerId','description','endDate','price','priceScaleType','priceScaleValue','reductionAdditions','salesChannel','startDate'];

function toFiniteNumber(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function normalizeScaleValue(value) {
  const v = value === null || value === undefined ? DEFAULT_SCALE_VALUE : value;
  const n = toFiniteNumber(v);
  if (n === null) return DEFAULT_SCALE_VALUE;
  const r = Math.round((n||0)*1e5)/1e5;
  const s = r.toFixed(5);
  return s.includes('.') ? s.replace(/\.?0+$/,'') : s;
}

function isGeneralTierZeroPrice(row) {
  if (!row || (row.customerId !== null && row.customerId !== undefined && row.customerId !== '')) return false;
  return normalizeScaleValue(row.priceScaleValue) === DEFAULT_SCALE_VALUE;
}

function isCurrentAt(row, ts) {
  const s = toFiniteNumber(row.startDate);
  const e = toFiniteNumber(row.endDate);
  return (s === null ? true : s <= ts) && (e === null ? true : e >= ts);
}

function toDistributionChannelKey(entry) {
  if (typeof entry === 'string') return entry.trim();
  if (entry && typeof entry === 'object' && entry.key != null) return String(entry.key).trim();
  return '';
}

function sanitizePriceRow(row) {
  const out = {};
  for (const key of WRITEABLE_PRICE_KEYS) {
    const v = row[key];
    if (v !== null && v !== undefined) {
      out[key] = key === 'reductionAdditions' ? JSON.parse(JSON.stringify(Array.isArray(v)?v:[])) : v;
    }
  }
  return out;
}

function buildTargetChannels(article, activeSalesChannels, sourceSalesChannel) {
  const out = { gross: [], net: [] };
  const seen = new Set();
  const avail = Array.isArray(article.availableForSalesChannels)
    ? new Set(article.availableForSalesChannels.map(String)) : null;
  for (const entry of activeSalesChannels) {
    const key = toDistributionChannelKey(entry);
    if (!key || key === sourceSalesChannel || seen.has(key)) continue;
    seen.add(key);
    if (avail && avail.size > 0 && !avail.has(key)) continue;
    if (key.startsWith('GROSS')) out.gross.push(key);
    else if (key.startsWith('NET')) out.net.push(key);
  }
  return out;
}

const articles = $input.all();
const activeSalesChannels = $('weclapp GET salesChannel activeSalesChannels').first().json.result || [];
const constants = $('Constants').first().json;
const sourceSalesChannel = constants.sourceSalesChannel || DEFAULT_SOURCE_SALES_CHANNEL;
const now = constants.effectiveTimestamp;

const results = [];
const skipped = [];
const errors = [];

for (let i = 0; i < articles.length; i++) {
  const article = articles[i].json;
  try {
    const articlePrices = Array.isArray(article.articlePrices) ? article.articlePrices : [];
    const sourceRows = articlePrices.filter(row =>
      row.salesChannel === sourceSalesChannel && isGeneralTierZeroPrice(row) && isCurrentAt(row, now)
    );
    if (sourceRows.length === 0) {
      skipped.push({ articleId: article.id, articleNumber: article.articleNumber, status: 'skipped_missing_source_price' });
      continue;
    }
    const targetChannels = buildTargetChannels(article, activeSalesChannels, sourceSalesChannel);
    const managedChannels = [...targetChannels.gross, ...targetChannels.net];
    results.push({
      json: {
        articleId: article.id,
        articleNumber: article.articleNumber,
        status: 'dry_run_update_ready',
        __dryRun: true,
        __blockedBy: 'issue#30: article.updatePrices composite not wired to execute() in Weclapp.node.ts',
        sourcePrice: sourceRows[0].price,
        targetChannels: managedChannels,
        requestBody: { articlePrices: articlePrices.map(sanitizePriceRow) },
      },
      pairedItem: { item: i },
    });
  } catch (err) {
    errors.push({ articleId: article.id, articleNumber: article.articleNumber, error: err.message });
  }
}

if (results.length === 0) {
  return [{
    json: { __summaryOnly: true, totalArticles: articles.length, skipped, errors, message: 'DRY RUN: no articles to update' },
    pairedItem: { item: 0 },
  }];
}
return results;
})();
